// Example Mod — +20% credits every time the player picks a modifier.
// Patches selectMod, which is called whenever a modifier card is clicked.

var _orig = window.selectMod;

window.selectMod = function(k, creditCost, isFree) {
  _orig(k, creditCost, isFree);
  addCreditPct(20);
  updateHUD();
};

return {
  unload: function() {
    window.selectMod = _orig;
  }
};
